import subprocess,time
def sc(*a):
    try: subprocess.run(['systemctl']+list(a),timeout=30)
    except Exception: pass
for i in range(1,33): sc('reset-failed','atlas-enrich-pool@%d.service'%i)
for b in range(1,33,4):
    for i in range(b,min(b+4,33)): sc('restart','atlas-enrich-pool@%d.service'%i)
    time.sleep(6)
print('pool restarted 32x16 staggered (PG-safe)')
